import base64

from PyQt6.QtGui import QPixmap
from PyQt6.QtCore import QByteArray, Qt

# Logo EDF encode en base64, avec une variante au texte blanc
# precalculee pour les fonds sombres (evite tout traitement au lancement)
_LOGO_B64 = ""

_LOGO_WHITE_B64 = ""


def get_edf_logo_pixmap(max_width=180, max_height=70, white_text=False):
    raw = base64.b64decode(_LOGO_WHITE_B64 if white_text else _LOGO_B64)
    pixmap = QPixmap()
    pixmap.loadFromData(QByteArray(raw), "PNG")
    return pixmap.scaled(
        max_width, max_height,
        Qt.AspectRatioMode.KeepAspectRatio,
        Qt.TransformationMode.SmoothTransformation,
    )
